{
	"name": "flue",
	"type": "module",
	"private": true,
	"license": "Apache-2.0",
	"packageManager": "pnpm@11.1.1",
	"engines": {
		"node": ">=22",
		"pnpm": ">=11 <12"
	},
	"scripts": {
		"dev": "turbo dev",
		"build": "turbo build",
		"test": "turbo test",
		"test:integration": "pnpm --dir packages/cli run test:integration:cloudflare",
		"check": "turbo run build check:lint check:types && turbo run test",
		"check:lint": "biome lint . && knip",
		"check:knip": "knip",
		"check:types": "turbo run check:types --filter=!apps-www",
		"format": "turbo run format:lint format:style",
		"format:lint": "biome check . --write",
		"format:style": "prettier . --cache --write --list-different"
	},
	"devDependencies": {
		"@biomejs/biome": "^2.2.0",
		"@flue/runtime": "workspace:*",
		"@types/node": "^22.10.10",
		"bgproc": "^0.3.0",
		"knip": "^6.14.2",
		"prettier": "^3.4.2",
		"turbo": "^2.3.3",
		"typescript": "^6.0.3"
	},
	"dependencies": {
		"just-bash": "^3.0.1",
		"valibot": "^1.1.0"
	},
	"pnpm": {
		"overrides": {
			"typescript": "6.0.3"
		}
	}
}

{
	"name": "linkswift",
	"version": "1.1.3.1",
	"description": "一个基于 JavaScript 的网盘文件下载地址获取工具",
	"main": "eslint.config.js",
	"scripts": {
		"test": "echo \"Error: no test specified\" && exit 1",
		"check": "npx eslint . --fix"
	},
	"repository": {
		"type": "git",
		"url": "git+https://github.com/hmjz100/LinkSwift.git"
	},
	"keywords": [
		"linkswift",
		"link",
		"swift",
		"download",
		"file",
		"address",
		"get"
	],
	"author": "hmjz100",
	"license": "AGPL-3.0",
	"type": "commonjs",
	"bugs": {
		"url": "https://github.com/hmjz100/LinkSwift/issues"
	},
	"homepage": "https://github.com/hmjz100/LinkSwift#readme",
	"devDependencies": {
		"@eslint/js": "^10.0.1",
		"eslint": "^10.2.1"
	}
}
